// Expenses Page
import React, { useEffect, useState } from 'react';
import { expenseService, categoryService } from '../services/api';
import useCurrency from '../hooks/useCurrency';
import './ExpensesPage.css';
import { FiEdit2, FiTrash2, FiPlus } from 'react-icons/fi';

/**
 * ExpensesPage - Manage expenses
 */
const ExpensesPage = () => {
  const [expenses, setExpenses] = useState([]);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [formData, setFormData] = useState({
    amount: '',
    categoryId: '',
    expenseDate: new Date().toISOString().split('T')[0],
    description: '',
    paymentMethod: 'CASH',
  });
  const [customCategory, setCustomCategory] = useState('');
  const { format } = useCurrency();

  useEffect(() => {
    fetchExpenses();
    fetchCategories();
  }, []);

  const fetchExpenses = async () => {
    try {
      const response = await expenseService.getAll();
      setExpenses(response.data);
    } catch (err) {
      setError('Failed to load expenses');
    } finally {
      setLoading(false);
    }
  };

  const fetchCategories = async () => {
    try {
      const response = await categoryService.getAll();
      setCategories(response.data);
    } catch (err) {
      console.error('Failed to load categories');
    }
  };

  const handleFormChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      let finalCategoryId = formData.categoryId;

      if (finalCategoryId === 'OTHER') {
        if (!customCategory.trim()) {
          setError('Please enter a custom category name');
          return;
        }
        // Create new category via API
        const catRes = await categoryService.create({
          name: customCategory.trim(),
          color: '#808080',
          icon: 'folder'
        });
        finalCategoryId = catRes.data.id;
        fetchCategories(); // Refresh categories list
      }

      const payload = { ...formData, categoryId: finalCategoryId };

      if (editingId) {
        await expenseService.update(editingId, payload);
      } else {
        await expenseService.create(payload);
      }
      fetchExpenses();
      resetForm();
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to save expense');
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure?')) {
      try {
        await expenseService.delete(id);
        fetchExpenses();
      } catch (err) {
        setError('Failed to delete expense');
      }
    }
  };

  const handleEdit = (expense) => {
    setFormData({
      amount: expense.amount,
      categoryId: expense.categoryId,
      expenseDate: expense.expenseDate,
      description: expense.description,
      paymentMethod: expense.paymentMethod,
    });
    setEditingId(expense.id);
    setShowForm(true);
  };

  const resetForm = () => {
    setFormData({
      amount: '',
      categoryId: '',
      expenseDate: new Date().toISOString().split('T')[0],
      description: '',
      paymentMethod: 'CASH',
    });
    setCustomCategory('');
    setEditingId(null);
    setShowForm(false);
  };

  if (loading) {
    return (
      <div className="loading">
        <div className="spinner"></div>
      </div>
    );
  }

  return (
    <div className="expenses-page">
      <div className="page-header">
        <h1>Expenses</h1>
        <button
          className="btn btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          <FiPlus /> Add Expense
        </button>
      </div>

      {error && <div className="alert alert-danger">{error}</div>}

      {/* Form */}
      {showForm && (
        <div className="expense-form card">
          <h2>{editingId ? 'Edit' : 'Add New'} Expense</h2>
          <form onSubmit={handleSubmit}>
            <div className="form-row">
              <div className="form-group">
                <label className="form-label">Amount</label>
                <input
                  type="number"
                  name="amount"
                  value={formData.amount}
                  onChange={handleFormChange}
                  className="form-input"
                  placeholder="0.00"
                  step="0.01"
                  required
                />
              </div>

              <div className="form-group">
                <label className="form-label">Category</label>
                <select
                  name="categoryId"
                  value={formData.categoryId}
                  onChange={handleFormChange}
                  className="form-select"
                  required
                >
                  <option value="">Select Category</option>
                  {categories.map((cat) => (
                    <option key={cat.id} value={cat.id}>
                      {cat.name}
                    </option>
                  ))}
                  <option value="OTHER">+ Other (Add New)</option>
                </select>
              </div>

              <div className="form-group">
                <label className="form-label">Date</label>
                <input
                  type="date"
                  name="expenseDate"
                  value={formData.expenseDate}
                  onChange={handleFormChange}
                  className="form-input"
                  required
                />
              </div>
            </div>

            {formData.categoryId === 'OTHER' && (
              <div className="form-group" style={{ marginBottom: '15px' }}>
                <label className="form-label">New Category Name</label>
                <input
                  type="text"
                  value={customCategory}
                  onChange={(e) => setCustomCategory(e.target.value)}
                  className="form-input"
                  placeholder="E.g., Pet Supplies, Gym, etc."
                  required
                />
              </div>
            )}

            <div className="form-group">
              <label className="form-label">Description</label>
              <input
                type="text"
                name="description"
                value={formData.description}
                onChange={handleFormChange}
                className="form-input"
                placeholder="Enter description"
              />
            </div>

            <div className="form-group">
              <label className="form-label">Payment Method</label>
              <select
                name="paymentMethod"
                value={formData.paymentMethod}
                onChange={handleFormChange}
                className="form-select"
              >
                <option>CASH</option>
                <option>CARD</option>
                <option>ONLINE</option>
                <option>BANK_TRANSFER</option>
              </select>
            </div>

            <div className="form-actions">
              <button type="submit" className="btn btn-primary">
                {editingId ? 'Update' : 'Save'} Expense
              </button>
              <button type="button" className="btn btn-secondary" onClick={resetForm}>
                Cancel
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Expenses Table */}
      <div className="card">
        <table className="table">
          <thead>
            <tr>
              <th>Date</th>
              <th>Category</th>
              <th>Description</th>
              <th>Amount</th>
              <th>Method</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {expenses.map((expense) => (
              <tr key={expense.id}>
                <td>{new Date(expense.expenseDate).toLocaleDateString()}</td>
                <td>{expense.categoryName}</td>
                <td>{expense.description || '-'}</td>
                <td className="amount">{format(expense.amount)}</td>
                <td>{expense.paymentMethod}</td>
                <td className="actions">
                  <button
                    className="btn-icon"
                    onClick={() => handleEdit(expense)}
                    title="Edit"
                  >
                    <FiEdit2 />
                  </button>
                  <button
                    className="btn-icon danger"
                    onClick={() => handleDelete(expense.id)}
                    title="Delete"
                  >
                    <FiTrash2 />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default ExpensesPage;
